/* practice with Dukkha */
#include <stdio.h>

int min(int a, int b) { return a < b ? a : b; }
int max(int a, int b) { return a > b ? a : b; }

int main() {
	int hp, atk, def, hp_, atk_, def_, h, a, d, ans, na, nd, nh;

	scanf("%d%d%d%d%d%d%d%d%d", &hp, &atk, &def, &hp_, &atk_, &def_, &h, &a, &d);
	ans = 0x3f3f3f3f;
	for (na = max(0, def_ + 1 - atk); na <= max(0, def_ + hp_ - atk); na++)
		for (nd = 0; nd <= max(0, atk_ - def); nd++) {
			int atk1 = atk + na - def_;
			int t = (hp_ + atk1 - 1) / atk1;

			nh = max(0, t * max(0, atk_ - def - nd) + 1 - hp);
			ans = min(ans, na * a + nd * d + nh * h);
		}
	printf("%d\n", ans);
	return 0;
}

